### JavaScript to Populate UI

```javascript
function populateAlerts(alerts) {
  const alertRows = document.getElementById("alertRows");

  alerts.forEach((alert) => {
    const row = document.createElement("tr");

    // Create columns for each field and add them to the row
    row.innerHTML = `
      <td>${alert.priority_score}</td>
      <td>${alert.customer_id}</td>
      <td>$${alert.amount.toFixed(2)}</td>
      <td>${alert.rule_id}</td>
      <td>${alert.status}</td>
      <td><button onclick="showDetails('${alert.alert_id}')">View</button></td>
    `;

    alertRows.appendChild(row);
  });
}

function showDetails(alertId) {
  const alert = getAlertById(alertId); // Function to fetch the specific alert details

  document.getElementById("alertsTable").style.display = "none";
  document.getElementsByClassName("details-panel")[0].style.display = "block";

  populateTransactionHistory(alert.evidence_details.transaction_history);
  populateCustomerProfile(alert.evidence_details.customer_profile);
  populateRelatedDocuments(alert.evidence_details.related_documents);
}

function markAsReviewed(status) {
  const alertId = getSelectedAlert().alert_id; // Function to fetch the selected alert ID
  updateStatusInDatabase(alertId, status); // Update database with new status

  document.getElementById("alertsTable").style.display = "block";
  document.getElementsByClassName("details-panel")[0].style.display = "none";
}

function populateTransactionHistory(transactions) {
  const transactionList = document.getElementById("transactionHistory");

  transactions.forEach((transaction) => {
    transactionList.innerHTML += `<li>${transaction.transaction_id}: $${transaction.amount.toFixed(2)} on ${new Date(transaction.timestamp).toLocaleString()}</li>`;
  });
}

function populateCustomerProfile(profile) {
  const customerDetails = document.getElementById("customerProfile");

  for (let key in profile) {
    if (profile.hasOwnProperty(key)) {
      customerDetails.innerHTML += `<dt>${key}</dt><dd>${profile[key]}</dd>`;
    }
  }
}

function populateRelatedDocuments(documents) {
  const documentList = document.getElementById("relatedDocuments");

  documents.forEach((document) => {
    documentList.innerHTML += `<li><a href="${document.document_id}">${document.type} - ${new Date(document.timestamp).toLocaleString()}</a></li>`;
  });
}
```

### Conclusion

By providing analysts with a well-structured review queue that includes all necessary details and evidence, you enable them to quickly assess the risk level of each transaction while ensuring thoroughness. This approach enhances both efficiency and compliance in your AML system.

